598	function buildWeeklyConfig(state: PlanEditorState): string | null {
599	  if (state.scheduleMode !== "weekly_fixed") return null;
600	
601	  const config: Record<string, string> = {};
602	  Object.entries(state.weeklyDayMap).forEach(([day, type]) => {
603	    if (type !== null) {
604	      // We use a placeholder — the actual biz_key will be set after save
605	      config[day] = type;
606	    }
607	  });
608	  return JSON.stringify(config);
609	}
