1	/**
2	 * HistoryScreen
3	 *
4	 * Main screen for Tab 3 (History) with 4-segment control:
5	 * 历史/进步/容量/PR with animated transitions.
6	 *
7	 * Follows the injected-props pattern for testability:
8	 * receives all data via props instead of using hooks internally.
9	 */
10	
11	import React, { useState } from "react";
12	import {
13	  View,
14	  Text,
15	  ScrollView,
16	  TouchableOpacity,
17	  StyleSheet,
18	  Alert,
19	} from "react-native";
20	import { Colors, Typography, Spacing } from "@utils/constants";
21	import { HISTORY_SEGMENTS } from "./history-helpers";
22	import type { HistorySegment } from "./history-helpers";
23	import {
24	  formatHistoryCardDate,
25	  computeSessionTotalVolume,
26	  formatVolume,
27	  getTrainingTypeLabel,
28	  getExercisesWithPR,
29	  filterSessionsByType,
30	  sortSessionsByDateDescending,
31	  isBacklogSession,
32	  formatSatisfaction,
33	} from "./history-helpers";
34	import type { VolumeDataPoint, VolumeSummary } from "./history-helpers";
35	import { HistoryCard } from "./HistoryCard";
36	import type { ExerciseSummary } from "./HistoryCard";
37	import { EmptyHistory } from "./EmptyHistory";
38	import { ProgressPanel } from "./ProgressPanel";
39	import type { ExerciseOption } from "./ProgressPanel";
40	import { VolumePanel } from "./VolumePanel";
41	import { PRPanel } from "./PRPanel";
42	import type { PRCardData } from "./PRPanel";
43	import { CalendarFilterTabs } from "../calendar/CalendarFilterTabs";
44	import type { FilterType } from "../calendar/CalendarFilterTabs";
45	import type {
46	  WorkoutSession,
47	  WorkoutExercise,
48	  WorkoutSet,
49	  PersonalRecordEntry,
50	  Feeling,
51	  Exercise,
52	} from "../../types";
53	
54	// ============================================================
55	// Props Interface (injected-props pattern)
56	// ============================================================
57	
58	export interface HistoryScreenProps {
59	  /** All completed/partial workout sessions */
60	  sessions: WorkoutSession[];
61	  /** Workout exercises grouped by session biz_key */
62	  exercisesBySession: Map<bigint, WorkoutExercise[]>;
63	  /** Workout sets grouped by workout exercise biz_key */
64	  setsByExercise: Map<bigint, WorkoutSet[]>;
65	  /** All PR entries */
66	  prs: PersonalRecordEntry[];
67	  /** Feelings grouped by session biz_key */
68	  feelingsBySession: Map<bigint, Feeling>;
69	  /** All exercises (for name lookup) */
70	  exercises: Exercise[];
71	  /** Progress chart data */
72	  progressData: Array<{
73	    date: string;
74	    value: number;
75	    isPR: boolean;
76	  }>;
77	  /** Exercises available for progress selector */
78	  progressExercises: ExerciseOption[];
79	  /** Volume chart data */
80	  volumeData: VolumeDataPoint[];
81	  /** Volume summary */
82	  volumeSummary: VolumeSummary;
83	  /** Formatted week change string */
84	  volumeWeekChange: string;
85	  /** PR cards for PR panel */
86	  prCards: PRCardData[];
87	  /** Navigate to workout detail edit */
88	  onEditSession: (sessionBizKey: bigint) => void;
89	  /** Delete session handler */
90	  onDeleteSession: (sessionBizKey: bigint) => void;
91	  /** Exercise selected for progress panel */
92	  selectedExerciseBizKey: bigint | null;
93	  /** Callback when exercise selected in progress panel */
94	  onExerciseSelect: (bizKey: bigint) => void;
95	}
96	
97	// ============================================================
98	// Component
99	// ============================================================
100	
101	export function HistoryScreen({
102	  sessions,
103	  exercisesBySession,
104	  setsByExercise,
105	  prs,
106	  feelingsBySession,
107	  exercises,
108	  progressData,
109	  progressExercises,
110	  volumeData,
111	  volumeSummary,
112	  volumeWeekChange,
113	  prCards,
114	  onEditSession,
115	  onDeleteSession,
116	  selectedExerciseBizKey,
117	  onExerciseSelect,
118	}: HistoryScreenProps) {
119	  const [activeSegment, setActiveSegment] =
120	    useState<HistorySegment["key"]>("history");
121	  const [typeFilter, setTypeFilter] = useState<FilterType>(null);
122	
123	  // Exercise name lookup
124	  const exerciseNameMap = new Map<bigint, string>();
125	  for (const ex of exercises) {
126	    exerciseNameMap.set(ex.biz_key, ex.exercise_name);
127	  }
128	
129	  // Filter and sort sessions for history panel
130	  const filteredSessions = sortSessionsByDateDescending(
131	    filterSessionsByType(sessions, typeFilter),
132	  );
133	
134	  // Determine selected exercise name for progress chart title
135	  const selectedExerciseName = selectedExerciseBizKey
136	    ? (exerciseNameMap.get(selectedExerciseBizKey) ?? "")
137	    : "";
138	
139	  // Empty state
140	  if (sessions.length === 0) {
141	    return (
142	      <View style={styles.container}>
143	        <View style={styles.navBar}>
144	          <Text style={styles.navTitle}>训练记录</Text>
145	        </View>
146	        <EmptyHistory />
147	      </View>
148	    );
149	  }
150	
151	  return (
152	    <View style={styles.container}>
153	      <View style={styles.navBar}>
154	        <Text style={styles.navTitle}>训练记录</Text>
155	      </View>
156	
157	      <ScrollView
158	        style={styles.scrollView}
159	        contentContainerStyle={styles.scrollContent}
160	        showsVerticalScrollIndicator={false}
161	      >
162	        {/* Segmented Control */}
163	        <View style={styles.segmented}>
164	          {HISTORY_SEGMENTS.map((segment) => (
165	            <TouchableOpacity
166	              key={segment.key}
167	              style={[
168	                styles.segOption,
169	                activeSegment === segment.key && styles.segOptionActive,
170	              ]}
171	              onPress={() => setActiveSegment(segment.key)}
172	              activeOpacity={0.7}
173	              testID={`${segment.key}-tab`}
174	            >
175	              <Text
176	                style={[
177	                  styles.segText,
178	                  activeSegment === segment.key && styles.segTextActive,
179	                ]}
180	              >
181	                {segment.label}
182	              </Text>
183	            </TouchableOpacity>
184	          ))}
185	        </View>
186	
187	        {/* Panel Content */}
188	        {activeSegment === "history" && (
189	          <View testID="history-list">
190	            {/* Training type filter */}
191	            <CalendarFilterTabs
192	              activeFilter={typeFilter}
193	              onFilterChange={setTypeFilter}
194	              testID="type-filter-btn"
195	            />
196	
197	            {filteredSessions.length === 0 ? (
198	              <View style={styles.emptyFilter}>
199	                <Text style={styles.emptyFilterText}>没有匹配的训练记录</Text>
200	              </View>
201	            ) : (
202	              filteredSessions.map((session) => {
203	                const sessionExercises =
204	                  exercisesBySession.get(session.biz_key) ?? [];
205	                const feeling = feelingsBySession.get(session.biz_key);
206	                const prExercises = getExercisesWithPR(
207	                  prs,
208	                  session.session_date,
209	                );
210	
211	                // Build exercise summaries
212	                const exerciseSummaries: ExerciseSummary[] =
213	                  sessionExercises.map((we) => {
214	                    const sets = setsByExercise.get(we.biz_key) ?? [];
215	                    const completedSets = sets.filter(
216	                      (s) => s.is_completed === 1,
217	                    );
218	                    const weight =
219	                      completedSets.length > 0
220	                        ? (completedSets[0].actual_weight ?? 0)
221	                        : (we.suggested_weight ?? 0);
222	                    const reps =
223	                      completedSets.length > 0
224	                        ? (completedSets[0].actual_reps ?? we.target_reps)
225	                        : we.target_reps;
226	
227	                    return {
228	                      exerciseName:
229	                        exerciseNameMap.get(we.exercise_biz_key) ?? "",
230	                      weight,
231	                      reps,
232	                      sets: completedSets.length || we.target_sets,
233	                      isPR: prExercises.has(we.exercise_biz_key),
234	                    };
235	                  });
236	
237	                // Compute volume
238	                let totalVolume = 0;
239	                for (const we of sessionExercises) {
240	                  const sets = setsByExercise.get(we.biz_key) ?? [];
241	                  totalVolume += computeSessionTotalVolume(sets);
242	                }
243	
244	                return (
245	                  <HistoryCard
246	                    key={String(session.biz_key)}
247	                    testID={`history-record-${session.biz_key.toString()}`}
248	                    formattedDate={formatHistoryCardDate(session.session_date)}
249	                    typeLabel={getTrainingTypeLabel(session.training_type)}
250	                    trainingType={session.training_type}
251	                    exercises={exerciseSummaries}
