1	/**
2	 * ProgressPanel
3	 *
4	 * Shows exercise selector dropdown + line chart (date vs weight)
5	 * with PR points highlighted green.
6	 * Uses View-based rendering for chart compatibility.
7	 */
8	
9	import React from "react";
10	import {
11	  View,
12	  Text,
13	  StyleSheet,
14	  TouchableOpacity,
15	  ScrollView,
16	} from "react-native";
17	import { Colors, Typography, Spacing } from "@utils/constants";
18	import type { ProgressDataPoint } from "../exercise/exercise-helpers";
19	
20	export interface ExerciseOption {
21	  exerciseBizKey: bigint;
22	  exerciseName: string;
23	}
24	
25	export interface ProgressPanelProps {
26	  /** Available exercises for the selector */
27	  exercises: ExerciseOption[];
28	  /** Currently selected exercise biz_key */
29	  selectedExerciseBizKey: bigint | null;
30	  /** Callback when exercise is selected */
31	  onExerciseSelect: (bizKey: bigint) => void;
32	  /** Progress data points for the selected exercise */
33	  progressData: ProgressDataPoint[];
34	  /** Chart title (e.g., "深蹲重量趋势") */
35	  chartTitle: string;
36	  /** Subtitle (e.g., "近4次训练") */
37	  chartSubtitle: string;
38	}
39	
40	export function ProgressPanel({
41	  exercises,
42	  selectedExerciseBizKey,
43	  onExerciseSelect,
44	  progressData,
45	  chartTitle,
46	  chartSubtitle,
47	}: ProgressPanelProps) {
48	  return (
49	    <View>
50	      {/* Exercise selector */}
51	      <View style={styles.selectorWrapper} testID="exercise-selector">
52	        <ScrollView horizontal showsHorizontalScrollIndicator={false}>
53	          {exercises.map((exercise) => {
54	            const isSelected =
55	              exercise.exerciseBizKey === selectedExerciseBizKey;
56	            return (
57	              <TouchableOpacity
58	                key={String(exercise.exerciseBizKey)}
59	                style={[
60	                  styles.selectorOption,
61	                  isSelected && styles.selectorOptionActive,
62	                ]}
63	                onPress={() => onExerciseSelect(exercise.exerciseBizKey)}
64	                activeOpacity={0.7}
65	              >
66	                <Text
67	                  style={[
68	                    styles.selectorText,
69	                    isSelected && styles.selectorTextActive,
70	                  ]}
71	                >
72	                  {exercise.exerciseName}
73	                </Text>
74	              </TouchableOpacity>
75	            );
76	          })}
77	        </ScrollView>
78	      </View>
79	
80	      {/* Progress Chart */}
81	      <View style={styles.chartContainer} testID="progress-chart">
82	        <Text style={styles.chartTitle}>{chartTitle}</Text>
83	        <Text style={styles.chartSubtitle}>{chartSubtitle}</Text>
84	
85	        {progressData.length > 0 ? (
86	          <View style={styles.chartArea}>
87	            {/* Simplified chart rendering using Views */}
88	            {renderChart(progressData)}
89	          </View>
90	        ) : (
91	          <View style={styles.emptyChart}>
92	            <Text style={styles.emptyChartText}>暂无数据</Text>
93	          </View>
94	        )}
95	      </View>
96	    </View>
97	  );
98	}
99	
100	function renderChart(data: ProgressDataPoint[]): React.ReactNode {
101	  if (data.length === 0) return null;
102	
103	  const maxValue = Math.max(...data.map((d) => d.value));
104	  const minValue = Math.min(...data.map((d) => d.value));
105	  const range = maxValue - minValue || 1;
106	  const chartHeight = 160;
107	
108	  return (
109	    <View>
110	      {/* Data points as vertical bars */}
111	      <View style={chartStyles.container}>
112	        {data.map((point, index) => {
113	          const heightPercent = (point.value - minValue) / range;
114	          const barHeight = Math.max(4, heightPercent * chartHeight);
115	          const showLabel =
116	            index % Math.max(1, Math.floor(data.length / 4)) === 0;
117	
118	          return (
119	            <View key={index} style={chartStyles.barWrapper}>
120	              <Text
121	                style={[
122	                  chartStyles.valueLabel,
123	                  point.isPR && chartStyles.valueLabelPR,
124	                ]}
125	              >
126	                {point.value}
127	              </Text>
128	              <View
129	                style={[
130	                  chartStyles.bar,
131	                  {
132	                    height: barHeight,
133	                    backgroundColor: point.isPR
134	                      ? Colors.success
135	                      : Colors.accent,
136	                  },
137	                ]}
138	              />
139	              {showLabel && (
140	                <Text style={chartStyles.dateLabel}>{point.date.slice(5)}</Text>
141	              )}
142	            </View>
143	          );
144	        })}
145	      </View>
146	
147	      {/* PR legend */}
148	      {data.some((d) => d.isPR) && (
149	        <View style={chartStyles.legend}>
150	          <View style={chartStyles.legendDot} />
151	          <Text style={chartStyles.legendText}>PR</Text>
152	        </View>
153	      )}
154	    </View>
155	  );
156	}
157	
