1	/**
2	 * CalendarFilterTabs
3	 *
4	 * Training type filter tabs below the month header.
5	 * Options: 全部 / 推 / 拉 / 蹲 / 其他运动
6	 */
7	
8	import React from "react";
9	import { View, Text, TouchableOpacity, StyleSheet } from "react-native";
10	import { Colors, Typography } from "@utils/constants";
11	
12	export type FilterType = "push" | "pull" | "legs" | "custom" | null;
13	
14	export interface CalendarFilterTabsProps {
15	  /** Currently active filter (null = show all) */
16	  activeFilter: FilterType;
17	  /** Called when a filter is selected */
18	  onFilterChange: (filter: FilterType) => void;
19	  /** Optional testID for the container */
20	  testID?: string;
21	}
22	
23	const FILTER_OPTIONS: Array<{ key: FilterType; label: string }> = [
24	  { key: null, label: "全部" },
25	  { key: "push", label: "推" },
26	  { key: "pull", label: "拉" },
27	  { key: "legs", label: "蹲" },
28	  { key: "custom", label: "其他运动" },
29	];
30	
31	export function CalendarFilterTabs({
32	  activeFilter,
33	  onFilterChange,
34	  testID,
35	}: CalendarFilterTabsProps) {
36	  return (
37	    <View style={styles.container} testID={testID}>
38	      {FILTER_OPTIONS.map((option) => {
39	        const isActive =
40	          activeFilter === option.key ||
41	          (activeFilter === null && option.key === null);
42	
43	        return (
44	          <TouchableOpacity
45	            key={option.key ?? "all"}
46	            style={[styles.tab, isActive && styles.tabActive]}
47	            onPress={() => onFilterChange(option.key)}
48	            activeOpacity={0.7}
49	            accessibilityRole="button"
50	            accessibilityState={{ selected: isActive }}
51	            testID={
52	              option.key ? `filter-option-${option.key}` : "filter-option-all"
53	            }
54	          >
55	            <Text style={[styles.tabText, isActive && styles.tabTextActive]}>
56	              {option.label}
57	            </Text>
58	          </TouchableOpacity>
59	        );
60	      })}
61	    </View>
62	  );
63	}
64	
65	const styles = StyleSheet.create({
